          return {
            ...entry,
            content: '비밀글입니다.',
            guestName: entry.guestName,
          }
        }
      }
      return entry
    }\)

    return NextResponse.json\({
      entries: processedEntries,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil\(total / limit\),
      },
    }\)
  } catch \(error\) {
    console.error\('Guestbook GET error:', error\)
