const VALID_SEARCH_TYPES = ['title', 'content', 'author', 'titleComment'] as const

// GET: 게시글 목록 조회
export async function GET\(request: NextRequest\) {
  try {
    const { searchParams } = new URL\(request.url\)
    const categorySlug = searchParams.get\('category'\)
    const search = searchParams.get\('search'\)
    const searchType = searchParams.get\('searchType'\) || 'title'
    const { page, limit, skip } = parsePagination\(searchParams\)

    if \(search && !VALID_SEARCH_TYPES.includes\(searchType as typeof VALID_SEARCH_TYPES[number]\)\) {
      return NextResponse.json\(
        { error: '유효하지 않은 검색 유형입니다' },
        { status: 400 }
      \)
    }

    const where: Prisma.PostWhereInput = {
      isDeleted: false,
    }

    if \(categorySlug\) {
      where.category = { slug: categorySlug }
    }

    if \(search\) {
      switch \(searchType\) {
        case 'title':
          where.title = { contains: search }
          break
        case 'content':
          where.content = { contains: search }
          break
        case 'author':
          where.OR = [
            { user: { nickname: { contains: search } } },
            { guestName: { contains: search } },
          ]
          break
        case 'titleComment':
          where.OR = [
            { title: { contains: search } },
            { comments: { some: { content: { contains: search }, isDeleted: false } } },
          ]
          break
      }
    }

    const [posts, total] = await Promise.all\([
      prisma.post.findMany\({
        where,
        include: {
          user: {
            select: {
              id: true,
              nickname: true,
              profileImage: true,
            },
          },
          category: {
            select: {
              id: true,
              name: true,
              slug: true,
            },
          },
        },
        orderBy: [{ isPinned: 'desc' }, { createdAt: 'desc' }],
        skip,
        take: limit,
      }\),
      prisma.post.count\({ where }\),
    ]\)

    return NextResponse.json\({
      posts,
      pagination: {
        page,
        limit,
        total,
        totalPages: Math.ceil\(total / limit\),
      },
    }\)
  } catch \(error\) {
    console.error\('Posts GET error:', error\)
    return NextResponse.json\(
      { error: '게시글을 불러오는데 실패했습니다' },
      { status: 500 }
    \)
  }
}

