      where: { id: parseInt\(session.user.id\) },
      data: { lastLoginAt: new Date\(\) },
    }\)

    return NextResponse.json\({ success: true }\)
  } catch \(error\) {
    console.error\('활동 업데이트 오류:', error\)
    return NextResponse.json\({ error: '활동 업데이트에 실패했습니다.' }, { status: 500 }\)
